#include <stdio.h>
#include <gmp.h>

void fastPower(mpz_t result, const mpz_t base, unsigned long long exp){
    mpz_set_ui(result, 1);
    mpz_t b;
    mpz_init_set(b, base);
    while(exp){
        if(exp & 1ULL) mpz_mul(result, result, b);
        mpz_mul(b, b, b);
        exp >>= 1ULL;
    }
    mpz_clear(b);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned long long b_val, e;
        if(scanf("%llu %llu", &b_val, &e)!=2) break;
        mpz_t base, result;
        mpz_init_set_ui(base, b_val);
        mpz_init(result);
        fastPower(result, base, e);
        gmp_printf("%Zd\n", result);
        mpz_clear(base);
        mpz_clear(result);
    }
    return 0;
}

