using namespace std;
using boost::multiprecision::cpp_int;

cpp_int fastPower(cpp_int base, unsigned long long exp){
    cpp_int result = 1;
    while(exp){
        if(exp & 1ULL) result *= base;
        base *= base;
        exp >>= 1ULL;
    }
    return result;
}

